import React, { useState, useEffect } from 'react';
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid,
} from 'recharts';
import api from '../utils/api';

interface CanalCount {
  canal: string;
  _count: number;
}

interface CategorieCount {
  categorie: string;
  _count: number;
}

interface RecentLead {
  nom: string;
  score?: number;
  categorie?: string;
  createdAt: string;
}

interface Stats {
  totalLeads: number;
  totalMessages: number;
  openRate: number;
  clickRate: number;
  replyRate: number;
  byCanal: CanalCount[];
  byCategorie: CategorieCount[];
  recentLeads: RecentLead[];
}

interface ChartDataPoint {
  name: string;
  value: number;
}

// Tier display mapping
const TIER_LABEL: Record<string, string> = {
  CHAUD: 'Tier A',
  TIEDE: 'Tier B',
  FROID: 'Tier C',
};

const TIER_DOT: Record<string, string> = {
  CHAUD: 'bg-emerald-400',
  TIEDE: 'bg-blue-400',
  FROID: 'bg-zinc-500',
};

const TIER_TEXT: Record<string, string> = {
  CHAUD: 'text-emerald-400',
  TIEDE: 'text-blue-400',
  FROID: 'text-zinc-400',
};

// Static sparkline data for "leads over time"
const LEADS_OVER_TIME: { day: string; leads: number }[] = [
  { day: 'Mon', leads: 12 },
  { day: 'Tue', leads: 19 },
  { day: 'Wed', leads: 8 },
  { day: 'Thu', leads: 27 },
  { day: 'Fri', leads: 34 },
  { day: 'Sat', leads: 15 },
  { day: 'Sun', leads: 22 },
];

interface StatCardProps {
  label: string;
  value: number | string;
  unit?: string;
  trend?: string;
  trendUp?: boolean;
}

function StatCard({ label, value, unit = '', trend }: StatCardProps): React.ReactElement {
  return (
    <div className="flex flex-col gap-1 py-1">
      <p className="text-2xl font-bold text-zinc-100 tabular-nums leading-none tracking-tight">
        {value}
        {unit && <span className="text-zinc-600 text-sm font-normal ml-0.5">{unit}</span>}
      </p>
      <p className="text-[11px] text-zinc-500">{label}</p>
      {trend && (
        <p className="text-[10px] text-zinc-600 mt-0.5">{trend}</p>
      )}
    </div>
  );
}

const CustomTooltip = ({ active, payload, label }: any): React.ReactElement | null => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-zinc-900 border border-zinc-800 rounded-lg px-3 py-2 text-xs shadow-xl">
        <p className="text-zinc-400 mb-0.5">{label || payload[0].name}</p>
        <p className="text-zinc-100 font-semibold tabular-nums">{payload[0].value}</p>
      </div>
    );
  }
  return null;
};

export default function MonitorPage(): React.ReactElement {
  const [stats, setStats] = useState<Stats | null>(null);

  const fetchStats = async (): Promise<void> => {
    try {
      const { data } = await api.get('/monitor');
      setStats(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchStats();
    const interval = setInterval(fetchStats, 10000);
    return () => clearInterval(interval);
  }, []);

