          unit="%"
          trend="Last 30 days"
        />
        <StatCard
          label="Click rate"
          value={stats.clickRate}
          unit="%"
          trend="Last 30 days"
        />
        <StatCard
          label="Reply rate"
          value={stats.replyRate}
