                dataKey="day"
                stroke="transparent"
                tick={{ fill: '#52525b', fontSize: 10 }}
                axisLine={false}
                tickLine={false}
              />
              <YAxis
                stroke="transparent"
                tick={{ fill: '#52525b', fontSize: 10 }}
                axisLine={false}
